import { useState, useEffect, useRef, useCallback } from "react";


function ActivityInput({ newSlot, setNewSlot, addSlot, S, COLORS }) {
  const [showSugg, setShowSugg] = useState(false);
  const filtered = newSlot.label.length > 0
    ? ACTIVITY_SUGGESTIONS.filter(s => s.toLowerCase().includes(newSlot.label.toLowerCase()) && s.toLowerCase() !== newSlot.label.toLowerCase())
    : ACTIVITY_SUGGESTIONS;
  const handleChange = (e) => { setNewSlot(p => ({ ...p, label: toTitleCase(e.target.value) })); setShowSugg(true); };
  const pickSugg = (s) => { setNewSlot(p => ({ ...p, label: s })); setShowSugg(false); };
  return (
    <div style={{ marginBottom: 12 }}>
      <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
        <input type="time" style={{ ...S.input, flex: 1 }} value={newSlot.time} onChange={e => setNewSlot(p => ({ ...p, time: e.target.value }))} />
        <div style={{ flex: 2, position: "relative" }}>
          <input style={S.input} placeholder="Activity (e.g. Gym)" value={newSlot.label} onChange={handleChange}
            onFocus={() => setShowSugg(true)} onBlur={() => setTimeout(() => setShowSugg(false), 150)} autoComplete="off" />
          {showSugg && filtered.length > 0 && (
            <div style={{ position: "absolute", top: "100%", left: 0, right: 0, background: "#1a2236", border: `1px solid rgba(255,255,255,0.12)`, borderRadius: 10, zIndex: 99, maxHeight: 180, overflowY: "auto", marginTop: 4, boxShadow: "0 8px 24px rgba(0,0,0,0.4)" }}>
              {filtered.slice(0, 8).map(s => (
                <div key={s} onMouseDown={() => pickSugg(s)} style={{ padding: "9px 14px", fontSize: 14, color: "#f0f4ff", cursor: "pointer", borderBottom: "1px solid rgba(255,255,255,0.05)" }}
                  onMouseEnter={e => e.currentTarget.style.background = "rgba(0,212,170,0.1)"}
                  onMouseLeave={e => e.currentTarget.style.background = "transparent"}>{s}</div>
              ))}
            </div>
          )}
        </div>
      </div>
      <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 8 }}>
        <span style={{ fontSize: 13, color: "#8892aa", minWidth: 70 }}>Duration:</span>
        <input type="range" min="1" max="60" step="1" value={newSlot.duration || 30}
          onChange={e => setNewSlot(p => ({ ...p, duration: parseInt(e.target.value) }))}
          style={{ flex: 1, accentColor: "#00d4aa" }} />
        <span style={{ fontSize: 13, fontWeight: 700, color: "#00d4aa", minWidth: 50 }}>{newSlot.duration || 30} min</span>
        <button onClick={addSlot} style={{ ...S.btnSm, color: COLORS.accent, border: `1px solid ${COLORS.accent}`, padding: "8px 14px", whiteSpace: "nowrap" }}>+ Add</button>
      </div>
    </div>
  );
}


